import { ref, onMounted } from 'vue'
import profile from '@/api/profile'
import { ElMessage } from 'element-plus'

export function useModules() {
  const loading = ref(false)
  const modules = ref([])

  const fetchModulesData = async () => {
    loading.value = true
    try {
      const response = await profile.getModules()
      if (response.data?.code === 200) {
        modules.value = response.data.data.map(module => ({
          ...module,
          layout: {
            order: module.layout?.order || 999,
            visible: module.layout?.visible !== false
          }
        }))
      }
    } catch (error) {
      console.error('获取模块数据失败:', error)
      ElMessage.error('获取模块数据失败')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    modules,
    fetchModulesData
  }
}
